# Generated by google (gemini-2.5-flash)
# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import requests
import logging

# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    enrich_urls_header_key = 'x-enrich-url'
    enrichment_data_header_key = 'x-enriched-data'

    enriched_data_results = []

    if enrich_urls_header_key in headers:
        # Extract the list of URLs from the header value
        # Headers in Lambda@Edge are lists of dictionaries: [{'key': 'X-Enrich-URL', 'value': 'url1,url2'}]
        enrich_url_values = headers[enrich_urls_header_key][0]['value']
        urls = [url.strip() for url in enrich_url_values.split(',') if url.strip()]

        for url in urls:
            try:
                # Make an HTTP GET request to fetch data
                # Using a short timeout to prevent long delays in edge function execution
                response = requests.get(url, timeout=1)
                
                if response.status_code == 200:
                    # Attempt to parse as JSON, otherwise store as text
                    try:
                        data = response.json()
                    except json.JSONDecodeError:
                        data = response.text
                    
                    enriched_data_results.append({
                        'url': url,
                        'status': response.status_code,
                        'data': data
                    })
                    logger.info(f"Successfully fetched data from {url}")
                else:
                    logger.warning(f"Failed to fetch data from {url}: HTTP {response.status_code}")
                    enriched_data_results.append({
                        'url': url,
                        'status': response.status_code,
                        'error': f"HTTP {response.status_code}"
                    })

            except requests.exceptions.Timeout:
                logger.error(f"Timeout while fetching data from {url}")
                enriched_data_results.append({
                    'url': url,
                    'status': 'timeout',
                    'error': 'Request timed out'
                })
            except requests.exceptions.RequestException as e:
                logger.error(f"Error fetching data from {url}: {e}")
                enriched_data_results.append({
                    'url': url,
                    'status': 'error',
                    'error': str(e)
                })
            except Exception as e:
                logger.error(f"An unexpected error occurred for URL {url}: {e}")
                enriched_data_results.append({
                    'url': url,
                    'status': 'unexpected_error',
                    'error': str(e)
                })

    # Add the collected enrichment data to a new header in the request
    # It's best practice to JSON encode the data if it's structured, and then put it into a header.
    # Be mindful of header size limits (typically ~8KB per header in CloudFront).
    if enriched_data_results:
        json_encoded_data = json.dumps(enriched_data_results)
        # Ensure the header key is lowercase as CloudFront standardizes them this way in the request object
        headers[enrichment_data_header_key] = [{
            'key': enrichment_data_header_key, # The actual header key to be sent to origin
            'value': json_encoded_data
        }]
        logger.info(f"Added enrichment data to header: {enrichment_data_header_key}")
    else:
        logger.info("No enrichment URLs found or no data fetched successfully.")

    return request